from typing import List, Dict, Any
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    # If no filters provided, return original results
    if not filter_specs:
        return search_results

    # Normalize logic string
    logic = filter_logic.upper()
    if logic not in {"AND", "OR"}:
        raise ValueError(f"Unsupported filter_logic '{filter_logic}'. Use 'AND' or 'OR'.")

    # Convert SearchResult objects to dictionaries expected by MetadataFilterEngine
    result_dicts: List[Dict[str, Any]] = []
    for result in search_results:
        result_dicts.append(
            {
                "id": result.id,
                "score": result.score,
                "text": result.text,
                "metadata": result.metadata,
            }
        )

    filter_engine = MetadataFilterEngine()

    if logic == "AND":
        # Standard behavior: all filters must match
        filtered_dicts = filter_engine.apply_filters(result_dicts, filter_specs)
    else:
        # OR logic: keep results that match at least one of the specified filter conditions.
        # We achieve this by applying each single-field filter separately (AND within field),
        # then taking the union of all matching results.
        id_to_result: Dict[Any, Dict[str, Any]] = {}

        for field_name, field_filter in filter_specs.items():
            # Build a filter spec containing only this field
            single_filter_spec = {field_name: field_filter}
            matched = filter_engine.apply_filters(result_dicts, single_filter_spec)
            for r in matched:
                # Use result id as key; last one wins but they are identical
                id_to_result[r["id"]] = r

        filtered_dicts = list(id_to_result.values())

    # Convert filtered dictionaries back to SearchResult objects, preserving structure
    id_to_original: Dict[Any, SearchResult] = {r.id: r for r in search_results}
    filtered_results: List[SearchResult] = []
    for rd in filtered_dicts:
        original = id_to_original.get(rd["id"])
        if original is not None:
            filtered_results.append(original)

    return filtered_results

