from typing import List
from leann.api import LeannSearcher, SearchResult


def search_and_rank_by_metadata_field(
    index_path: str,
    query: str,
    rank_by_field: str,
    top_k: int = 5
) -> List[SearchResult]:
    """Search in an index and rank results by a metadata field value.

    Args:
        index_path: Path to the LEANN index file
        query: Search query string
        rank_by_field: Metadata field name to use for ranking (results with higher values ranked first)
        top_k: Number of results to return (default: 5)

    Returns:
        List of SearchResult objects, sorted by the specified metadata field value
        (descending), then by score (descending).

    Raises:
        FileNotFoundError: If the index file at ``index_path`` is not found.
    """
    try:
        # Initialize the searcher with the given index path
        searcher = LeannSearcher(index_path=index_path)
    except FileNotFoundError:
        # Propagate FileNotFoundError as required
        raise

    # Perform search
    results: List[SearchResult] = searcher.search(query=query, top_k=top_k)

    # Helper to safely extract ranking metadata field value
    def _get_rank_value(res: SearchResult):
        # SearchResult is typically dict-like; fall back to .get on metadata
        if isinstance(res, dict):
            value = res.get(rank_by_field)
            if value is None:
                metadata = res.get("metadata", {}) or {}
                value = metadata.get(rank_by_field)
        else:
            # For object-style SearchResult, use attributes/metadata dict if present
            value = getattr(res, rank_by_field, None)
            if value is None:
                metadata = getattr(res, "metadata", {}) or {}
                value = metadata.get(rank_by_field)

        # Missing field should rank last; treat as 0
        if value is None:
            return 0

        # Try to coerce to numeric for consistent ordering
        try:
            return float(value)
        except (TypeError, ValueError):
            # Fall back to string comparison; numeric-like values will already be handled
            return value

    # Sort by metadata field (descending) then by score (descending)
    # For dict-like SearchResult, score is typically under "score"; for object, .score
    def _get_score(res: SearchResult):
        if isinstance(res, dict):
            return float(res.get("score", 0.0))
        return float(getattr(res, "score", 0.0))

    ranked_results = sorted(
        results,
        key=lambda r: (_get_rank_value(r), _get_score(r)),
        reverse=True,
    )

    # Respect requested top_k size even after re-ranking (in case external callers
    # change searcher.search behavior to return more than requested)
    return ranked_results[:top_k]
